"use client";

import { useEffect, useState } from "react";
import { apiFetch } from "@/lib/api";
import BackToDashboard from "@/components/BackToDashboard";
import { isSuperAdmin } from "@/lib/auth";
import { Modal } from "@/components/ui/modal";
import Badge from "@/components/ui/badge/Badge";
import {
  Table,
  TableBody,
  TableCell,
  TableHeader,
  TableRow,
} from "@/components/ui/table";

type Customer = {
  id: string;
  full_name_ar: string;
  full_name_en?: string;
  mobile_number: string;
  national_id?: string;
  city?: string;
  address?: string;
  risk_level?: string;
  status?: string;
};

export default function CustomersPage() {
  const [page, setPage] = useState(1);
  const pageSize = 15;

  const [customers, setCustomers] = useState<Customer[]>([]);
  const [loading, setLoading] = useState(true);
  const [editingCustomer, setEditingCustomer] = useState<Customer | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [error, setError] = useState("");
  const [superAdmin, setSuperAdmin] = useState(false);

  const [form, setForm] = useState({
    full_name_ar: "",
    full_name_en: "",
    mobile_number: "",
    national_id: "",
    city: "",
    address: "",
  });

  useEffect(() => {
    loadCustomers();
    setSuperAdmin(isSuperAdmin());
  }, []);

  async function loadCustomers() {
    try {
      setLoading(true);
      const data = await apiFetch("/merchant/customers");
      setCustomers(data);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  function openAddModal() {
    setEditingCustomer(null);
    setForm({
      full_name_ar: "",
      full_name_en: "",
      mobile_number: "",
      national_id: "",
      city: "",
      address: "",
    });
    setIsModalOpen(true);
  }

  function openEditModal(customer: Customer) {
    setEditingCustomer(customer);
    setForm({
      full_name_ar: customer.full_name_ar || "",
      full_name_en: customer.full_name_en || "",
      mobile_number: customer.mobile_number || "",
      national_id: customer.national_id || "",
      city: customer.city || "",
      address: customer.address || "",
    });
    setIsModalOpen(true);
  }

  async function saveCustomer(e: React.FormEvent) {
    e.preventDefault();

    try {
      if (editingCustomer) {
        await apiFetch(`/merchant/customers/${editingCustomer.id}`, {
          method: "PATCH",
          body: JSON.stringify(form),
        });
      } else {
        await apiFetch("/merchant/customers", {
          method: "POST",
          body: JSON.stringify(form),
        });
      }

      setIsModalOpen(false);
      setEditingCustomer(null);
      await loadCustomers();
    } catch (err: any) {
      setError(err.message);
    }
  }

  async function deactivateCustomer(id: string) {
    if (!confirm("Deactivate this customer?")) return;

    try {
      await apiFetch(`/merchant/customers/${id}`, {
        method: "DELETE",
      });

      await loadCustomers();
    } catch (err: any) {
      setError(err.message);
    }
  }

  const totalPages = Math.ceil(customers.length / pageSize);

  const paginatedCustomers = customers.slice(
    (page - 1) * pageSize,
    page * pageSize
  );

  return (
    <main className="mx-auto max-w-7xl p-6 lg:p-8">
      <div className="mb-6 flex flex-wrap items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-semibold text-gray-800 dark:text-white/90">
            Manage Customers
          </h1>
          <p className="mt-1 text-sm text-gray-500 dark:text-gray-400">
            View, add, update, and deactivate customer records.
          </p>
        </div>

        <div className="flex items-center gap-3">
          <BackToDashboard />

          <button
            onClick={openAddModal}
            className="rounded-lg bg-brand-500 px-4 py-2.5 text-sm font-medium text-white hover:bg-brand-600"
          >
            Add Customer
          </button>
        </div>
      </div>

      {error && (
        <div className="mb-4 rounded-lg border border-error-200 bg-error-50 px-4 py-3 text-sm text-error-700 dark:border-error-500/30 dark:bg-error-500/10 dark:text-error-400">
          {error}
        </div>
      )}

      <div className="overflow-hidden rounded-xl border border-gray-200 bg-white dark:border-white/[0.05] dark:bg-white/[0.03]">
        <div className="max-w-full overflow-x-auto">
          <div className="min-w-[1100px]">
            <Table>
              <TableHeader className="border-b border-gray-100 dark:border-white/[0.05]">
                <TableRow>
                  {[
                    "Arabic Name",
                    "English Name",
                    "Mobile",
                    "National ID",
                    "City",
                    "Risk Level",
                    "Status",
                    "Actions",
                  ].map((header) => (
                    <TableCell
                      key={header}
                      isHeader
                      className="px-5 py-3 text-start text-theme-xs font-medium text-gray-500 dark:text-gray-400"
                    >
                      {header}
                    </TableCell>
                  ))}
                </TableRow>
              </TableHeader>

              <TableBody className="divide-y divide-gray-100 dark:divide-white/[0.05]">
                {loading ? (
                  <TableRow>
                    <TableCell className="px-5 py-6 text-center text-gray-500 dark:text-gray-400">
                      Loading customers...
                    </TableCell>
                  </TableRow>
                ) : paginatedCustomers.length === 0 ? (
                  <TableRow>
                    <TableCell className="px-5 py-6 text-center text-gray-500 dark:text-gray-400">
                      No customers found.
                    </TableCell>
                  </TableRow>
                ) : (
                  paginatedCustomers.map((customer) => (
                    <TableRow key={customer.id}>
                      <TableCell className="px-5 py-4 text-start">
                        <span className="block text-theme-sm font-medium text-gray-800 dark:text-white/90">
                          {customer.full_name_ar}
                        </span>
                        <span className="block text-theme-xs text-gray-500 dark:text-gray-400">
                          {customer.id}
                        </span>
                      </TableCell>

                      <TableCell className="px-4 py-3 text-theme-sm text-gray-500 dark:text-gray-400">
                        {customer.full_name_en || "-"}
                      </TableCell>

                      <TableCell className="px-4 py-3 text-theme-sm text-gray-500 dark:text-gray-400">
                        {customer.mobile_number}
                      </TableCell>

                      <TableCell className="px-4 py-3 text-theme-sm text-gray-500 dark:text-gray-400">
                        {customer.national_id || "-"}
                      </TableCell>

                      <TableCell className="px-4 py-3 text-theme-sm text-gray-500 dark:text-gray-400">
                        {customer.city || "-"}
                      </TableCell>

                      <TableCell className="px-4 py-3">
                        <Badge
                          size="sm"
                          color={
                            customer.risk_level === "low"
                              ? "success"
                              : customer.risk_level === "medium"
                              ? "warning"
                              : customer.risk_level === "high"
                              ? "error"
                              : "light"
                          }
                        >
                          {customer.risk_level || "unknown"}
                        </Badge>
                      </TableCell>

                      <TableCell className="px-4 py-3">
                        <Badge
                          size="sm"
                          color={
                            customer.status === "active"
                              ? "success"
                              : customer.status === "inactive"
                              ? "error"
                              : "warning"
                          }
                        >
                          {customer.status || "unknown"}
                        </Badge>
                      </TableCell>

                      <TableCell className="px-4 py-3">
                        <div className="flex items-center gap-2">
                          <button
                            onClick={() => openEditModal(customer)}
                            className="rounded-lg border border-gray-300 px-3 py-1.5 text-sm font-medium text-gray-700 hover:bg-gray-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
                          >
                            Edit
                          </button>

                          <button
                            onClick={() => deactivateCustomer(customer.id)}
                            className="rounded-lg bg-error-500 px-3 py-1.5 text-sm font-medium text-white hover:bg-error-600"
                          >
                            Deactivate
                          </button>
                        </div>
                      </TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          </div>
        </div>

        <div className="flex items-center justify-between border-t border-gray-100 px-5 py-4 dark:border-white/[0.05]">
          <button
            onClick={() => setPage((p) => Math.max(p - 1, 1))}
            disabled={page === 1}
            className="rounded-lg border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50 disabled:cursor-not-allowed disabled:opacity-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
          >
            Previous
          </button>

          <span className="text-sm text-gray-500 dark:text-gray-400">
            Page {page} of {totalPages || 1}
          </span>

          <button
            onClick={() => setPage((p) => Math.min(p + 1, totalPages))}
            disabled={page === totalPages || totalPages === 0}
            className="rounded-lg border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50 disabled:cursor-not-allowed disabled:opacity-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
          >
            Next
          </button>
        </div>
      </div>

      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        className="mx-4 max-w-[700px] p-6 lg:p-10"
      >
        <div>
          <h4 className="mb-2 text-2xl font-semibold text-gray-800 dark:text-white/90">
            {editingCustomer ? "Update Customer" : "Add New Customer"}
          </h4>

          <p className="mb-6 text-sm text-gray-500 dark:text-gray-400">
            Enter the customer details below.
          </p>

          {superAdmin && !editingCustomer && (
            <div className="mb-5 rounded-lg border border-warning-200 bg-warning-50 px-4 py-3 text-sm text-warning-700 dark:border-warning-500/30 dark:bg-warning-500/10 dark:text-warning-400">
              ⚠️ Super admin can view customers, but customer creation should normally be done by merchants.
            </div>
          )}

          <form onSubmit={saveCustomer}>
            <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
              <input
                className="h-11 rounded-lg border border-gray-300 px-4 py-2.5 text-sm text-gray-800 placeholder:text-gray-400 focus:border-brand-300 focus:outline-hidden focus:ring-3 focus:ring-brand-500/10 dark:border-gray-700 dark:bg-gray-900 dark:text-white/90"
                placeholder="Arabic Name"
                value={form.full_name_ar}
                onChange={(e) =>
                  setForm({ ...form, full_name_ar: e.target.value })
                }
                required
              />

              <input
                className="h-11 rounded-lg border border-gray-300 px-4 py-2.5 text-sm text-gray-800 placeholder:text-gray-400 focus:border-brand-300 focus:outline-hidden focus:ring-3 focus:ring-brand-500/10 dark:border-gray-700 dark:bg-gray-900 dark:text-white/90"
                placeholder="English Name"
                value={form.full_name_en}
                onChange={(e) =>
                  setForm({ ...form, full_name_en: e.target.value })
                }
              />

              <input
                className="h-11 rounded-lg border border-gray-300 px-4 py-2.5 text-sm text-gray-800 placeholder:text-gray-400 focus:border-brand-300 focus:outline-hidden focus:ring-3 focus:ring-brand-500/10 dark:border-gray-700 dark:bg-gray-900 dark:text-white/90"
                placeholder="Mobile"
                value={form.mobile_number}
                onChange={(e) =>
                  setForm({ ...form, mobile_number: e.target.value })
                }
                required
              />

              <input
                className="h-11 rounded-lg border border-gray-300 px-4 py-2.5 text-sm text-gray-800 placeholder:text-gray-400 focus:border-brand-300 focus:outline-hidden focus:ring-3 focus:ring-brand-500/10 dark:border-gray-700 dark:bg-gray-900 dark:text-white/90"
                placeholder="National ID"
                value={form.national_id}
                onChange={(e) =>
                  setForm({ ...form, national_id: e.target.value })
                }
              />

              <input
                className="h-11 rounded-lg border border-gray-300 px-4 py-2.5 text-sm text-gray-800 placeholder:text-gray-400 focus:border-brand-300 focus:outline-hidden focus:ring-3 focus:ring-brand-500/10 dark:border-gray-700 dark:bg-gray-900 dark:text-white/90"
                placeholder="City"
                value={form.city}
                onChange={(e) => setForm({ ...form, city: e.target.value })}
              />

              <input
                className="h-11 rounded-lg border border-gray-300 px-4 py-2.5 text-sm text-gray-800 placeholder:text-gray-400 focus:border-brand-300 focus:outline-hidden focus:ring-3 focus:ring-brand-500/10 dark:border-gray-700 dark:bg-gray-900 dark:text-white/90"
                placeholder="Address"
                value={form.address}
                onChange={(e) => setForm({ ...form, address: e.target.value })}
              />
            </div>

            <div className="mt-6 flex items-center justify-end gap-3">
              <button
                type="button"
                onClick={() => setIsModalOpen(false)}
                className="rounded-lg border border-gray-300 px-4 py-2.5 text-sm font-medium text-gray-700 hover:bg-gray-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
              >
                Cancel
              </button>

              <button
                type="submit"
                className="rounded-lg bg-brand-500 px-4 py-2.5 text-sm font-medium text-white hover:bg-brand-600"
              >
                {editingCustomer ? "Update Customer" : "Add Customer"}
              </button>
            </div>
          </form>
        </div>
      </Modal>
    </main>
  );
}